#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Entities
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.removeWithoutParent)]
    public class RemoveWithoutParentBehaviour : EntityBehaviourDefinition
    {
        public RemoveWithoutParentBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (!entity.Parent.ExistsAndAlive())
            {
                entity.Remove();
            }
        }
    }
}
